test('controller rotation updates use the same finite-value contract', () {
  final controller = FractalController(ModuleRegistry());
  addTearDown(controller.dispose);

  controller.updateRotation(Vector3(0.25, -0.5, 1.0));
  controller.updateRotation(Vector3(double.nan, double.infinity, 2.0));

  expect(controller.view.rotation, Vector3(0.25, -0.5, 2.0));
});

