edits.newText:
void updateRotation(Vector3 rotation) {
  _view = _view.copyWith(
    rotation: FractalViewInputBounds.normalizeRotation(
      candidate: rotation,
      current: _view.rotation,
    ),
  );
  notifyListeners();
}

